description:
کلاس پایه‌ای و انتزاعی برای تمام نودهای رابط کاربری گودو. این نود وظیفه پردازش مستقیم لنگرها، آفست‌ها، دریافت ورودی‌های ماوس از طریق فیلتر mouse_filter و مدیریت سیستم دریافت فوکوس ورودی را بر عهده دارد.

C#:
MouseFilter = MouseFilterEnum.Ignore;

کلاس پایه انتزاعی برای تمامی دکمه‌های رابط کاربری در گودو که به خودی خود چیزی رندر نمی‌کند. این نود مسئولیت مدیریت وضعیت‌های دکمه (عادی، فشرده، هاور، غیرفعال) و صدور سیگنال‌های فیزیکی نظیر pressed و toggled را بر عهده دارد.

C#:
ButtonPressed = true;

دکمه متنی و گرافیکی استاندارد و مجهز به سیستم تم که برای دکمه‌های منو و فرم‌ها استفاده می‌شود. این نود قابلیت نمایش هم‌زمان متن و آیکون گرافیکی را دارا بوده و از کلیدهای میانبر (Shortcut) سیستم کاملاً پشتیبانی می‌کند.

C#:
Pressed += () => GD.Print("دکمه کلیک شد!");

نسخه ویژه و بسیار پرکاربرد از کلاس دکمه‌ها که به جای رندر ساده، رفتارهای فیزیکی دکمه را بر اساس بافت‌های گرافیکی تخصیص‌یافته (هاور، فشرده، عادی) نمایش می‌دهد.

C#:
TextureNormal = GD.Load<Texture2D>("res://btn_normal.png");

دکمه‌ای شبیه به لینک‌های سنتی صفحات وب که معمولاً زیر آن خط کشیده شده و برای ارجاع به وب‌سایت‌ها یا باز کردن صفحات خارجی در بازی کاربرد دارد.

C#:
Uri = "https://godotengine.org";

دکمه‌ای دوحالته (باینری) که برای انتخاب گزینه‌ها در منوی تنظیمات کاربرد دارد. در صورتی که این نود به یک ButtonGroup متصل شود، به صورت خودکار رفتاری مشابه رادیو-باتن‌ها پیدا می‌کند.

C#:
Toggled += (toggledOn) => GD.Print("وضعیت: " + toggledOn);

یک سوئیچ گرافیکی دوحالته (روشن/خاموش) که از لحاظ منطق عملیاتی دقیقاً مشابه CheckBox است، اما از لحاظ بصری بیشتر برای فعال/غیرفعال کردن فوری برخی ویژگی‌ها طراحی شده است.

C#:
SetPressedNoSignal(true);

نود رندرکننده یک مستطیل ساده و مسطح که فقط یک رنگ ثابت و خالص (بدون نیاز به بافت خارجی) را روی صفحه نمایش می‌دهد.

C#:
Color = new Color(0.2f, 0.6f, 0.9f);

نود تخصصی رندر تصاویر رابط کاربری و المان‌های ثابت گرافیکی نظیر آیکون‌ها، باگ‌گراند منوها و نوارهای جانبی که از مدهای کشیدگی و کاشی‌کاری چندگانه پشتیبانی می‌کند.

C#:
ExpandMode = TextureRect.ExpandModeEnum.FitWidthProportional;

ابزاری فوق‌العاده کاربردی برای ساخت حاشیه‌ها و کادرهای دیالوگ. این نود با تقسیم تصویر به ۹ بخش مجزا، از دفرمه شدن و تار شدن گوشه‌های کادر در هنگام تغییر سایز کانتینر ممانعت می‌کند.

C#:
PatchMarginLeft = 15;

کنترلری ساده که از یک کلاس سبک استایل‌باکس بومی برای نمایش کادرها و باک‌گراندهای رابط کاربری بدون وجود دکمه‌ها و عناصر تعاملی استفاده می‌کند.

C#:
SelfModulate = new Color(1f, 1f, 1f, 0.8f);

نود اصلی نمایش متون ایستا و بدون استایل‌باکس داخلی در پروژه‌های گودو. این نود برای نمایش عبارات ساده، لودینگ، و هدهای بازی کاربرد داشته و از متدهایی مثل ترازبندی خودکار سود می‌برد.

C#:
Text = "امتیاز شما: 150";

پردازنده و نمایش‌دهنده قدرتمند متون مجهز به سیستم استایل‌دهی غنی (Bold, Italics, Color) با کدهای استاندارد BBCode. این نود ویژگی‌های منحصربه‌فردی نظیر افکت‌های متنی پویا (RichTextEffect) و لینک‌های فعال را به ارمغان می‌آورد.

C#:
AppendText("[color=red]خطای مهلک[/color]");

فیلد متنی تک‌خطی برای دریافت اطلاعات ورودی نظیر نام بازیکنان یا آدرس‌های کوتاه وب. این نود از کلیدهای میانبر استاندارد سیستم‌عامل (کپی، کات و پیست) به طور بومی پشتیبانی می‌کند.

C#:
PlaceholderText = "نام خود را وارد کنید...";

ویرایشگر متنی چندخطی مجهز به پشتیبانی از راست‌چین/چپ‌چین کردن پویا، ردیابی کاراکترهای مخفی و سیستم کنترلی مکان‌نما برای توسعه برنامه‌ها یا لاگین‌های متنی طولانی.

C#:
Text = "خط اول\nخط دوم";

کلاسی تخصصی ارث‌بری شده از TextEdit که برای نوشتن کدهای متنی در محیط ادیتورها بهینه‌سازی شده و دارای امکاناتی چون شماره خطوط، تاشدگی متدها و هایلایت نحوی است.

C#:
CodeCompletionEnabled = true;

کلاس پایه انتزاعی برای تمامی کنترل‌هایی که با مقادیر عددی در یک محدوده معین (دارای حداقل، حداکثر و گام تغییر) کار می‌کنند.

C#:
MinValue = 0.0; MaxValue = 100.0; Step = 1.0;

نود نمایش‌دهنده پیشرفت یک فرآیند بر مبنای عدد (مثل نوار لودینگ یا پر شدن نوار لول‌آپ) با افکت پرشدگی بومی افقی یا عمودی.

C#:
Value = 75.0;

نوار پیشرفت پیشرفته که به توسعه‌دهنده امکان می‌دهد با تخصیص تصاویر دلخواه به باک‌گراند، خط دور و بخش پرکننده، نوارهای جذاب سلامتی (HP) با مد پرشدگی دایره‌ای یا خطی طراحی کند.

C#:
FillMode = (int)TextureProgressBar.FillModeEnum.Clockwise;

کلاس پایه برای نوارهای اسکرول افقی (HScrollBar) و عمودی (VScrollBar) که با حرکت فیزیکی هندل خود به کاربر امکان جابه‌جا شدن در صفحات و لیست‌های طولانی را می‌دهد.

C#:
CustomMinimumSize = new Vector2(12, 0);

اسلایدرهای افقی (HSlider) و عمودی (VSlider) که برای تغییر دستی آسان مقادیر عددی مانند تنظیم سطح صدای بازی یا حساسیت ماوس در پنل تنظیمات استفاده می‌شوند.

C#:
ValueChanged += (val) => GD.Print("مقدار تغییر کرد: " + val);

نود ترکیبی عددی شامل یک فیلد متنی LineEdit داخلی و دو دکمه بالا و پایین برای افزایش و کاهش دقیق مقادیر عددی ریاضی.

C#:
GetLineEdit().ContextMenuEnabled = false;

کلاس پایه‌ای بسیار قدرتمند و انتزاعی برای کانتینرها که موقعیت و اندازه نودهای فرزند خود را که از کلاس Control هستند، طبق قوانین ریاضی به طور خودکار بازآرایی می‌کند.

C#:
QueueSort();

کلاس مرجع که عناصر فرزند را پشت‌سرهم در یک جهت فیزیکی (افقی یا عمودی) تراز می‌کند و در قالب کلاس‌های ویژه‌تری نظیر HBoxContainer ارائه می‌شود.

C#:
Alignment = BoxContainer.AlignmentMode.Center;

نوعی از کانتینر جعبه‌ای که تمام عناصر فرزند درون خود را بدون تداخل و به صورت کاملاً خودکار در قالب یک صف افقی منظم در کنار هم ردیف می‌کند.

C#:
AddChild(new Button { Text = "دکمه جدید" });

این کانتینر تمام عناصر و کنترل‌های فرزند را به صورت خودکار و زیر هم در قالب یک صف عمودی کاملاً هم‌تراز سازماندهی می‌نماید.

C#:
AddThemeConstantOverride("separation", 15);

کانتینری هوشمند جهت مرتب‌سازی چیدمان فرزندان در قالب جدول یا شبکه‌ای از سطرها و ستون‌ها با قابلیت تنظیم پویای تعداد ستون‌ها.

C#:
Columns = 4;

کانتینر اضافه کردن فضاهای خالی امن به دور عناصر ورودی؛ این نود حاشیه‌های ثابت خارجی را برای تمام فرزندان از چهار جهت کنترل می‌نماید.

C#:
AddThemeConstantOverride("margin_top", 100);

کانتینری که تمام عناصر فرزند را بدون وابستگی به اندازه آن‌ها، دقیقاً در مرکز نقطه تلاقی هندسی کادر بیرونی خود تراز و شناور نگاه می‌دارد.

C#:
UseMinimumSize = true;

کانتینر تخصصی که علاوه بر سازماندهی خودکار موقعیت فرزندان، یک باک‌گراند و حاشیه مبتنی بر تم و استایل‌باکس را دور تا دور فرزند خود ترسیم می‌کند.

C#:
AddThemeStyleboxOverride("panel", new StyleBoxFlat());

کانتینری که برای نمایش لیست‌های ورودی بزرگتر از اندازه قاب نمایش مجهز به نوارهای اسکرول داخلی داینامیک می‌شود.

C#:
ScrollHorizontal = 120;

کانتینری دارای اسلایدر میانی متحرک که به کاربر بازی اجازه می‌دهد به صورت داینامیک سهم فضای تخصیص‌یافته به دو کانتینر فرزند را در صفحه بازی تغییر دهد.

C#:
SplitOffset = 50;

کانتینری فوق‌العاده برای منوهای تبی؛ این نود به ازای هر فرزند، یک تب کلیک‌خور در بالای کادر ایجاد کرده و با کلیک روی آن فقط فرزند فعال را رندر می‌کند.

C#:
CurrentTab = 0;

نود رندرکننده تب‌ها به صورت افقی بدون ایجاد ساختار مخفی‌کننده یا سوئیچینگ اتوماتیک فرزندان. برای سناریوهایی که می‌خواهید کنترل محتوای تب‌ها را به طور دستی بنویسید بسیار بهینه است.

C#:
TabChanged += (index) => GD.Print("تب جدید: " + index);

کانتینری مجهز به امکان نمایش کل خروجی رندر شده یک ساب‌ویوپورت در بخش‌های دوبعدی رابط کاربری (مانند نمایش تصاویر سه‌بعدی آواتار در UI).

C#:
Stretch = true;

یک گرید نامحدود دوبعدی که زیربنای سیستم‌های شیدرنویسی بصری یا پیاده‌سازی سیستم دیالوگ‌نویسی درختی و اتصال المان‌های GraphNode است.

C#:
ConnectionRequest += (fromNode, fromPort, toNode, toPort) => ConnectNode(fromNode, fromPort, toNode, toPort);

نود پورت‌دار گرافیکی که در محیط کانتینری GraphEdit سازماندهی می‌شود و دارای متدهایی برای اتصال سیم‌های جریان داده بین ورودی و خروجی است.

C#:
SetSlot(0, true, 0, new Color(1, 1, 1), true, 0, new Color(1, 1, 1));

لیست پویای عمودی با پشتیبانی از ستون‌های چندگانه برای نمایش المان‌هایی نظیر کوله‌پشتی بازیکن، انتخاب کاراکترها یا لاگ‌ها به همراه آیکون و متن.

C#:
AddItem("آیتم جدید", GD.Load<Texture2D>("res://icon.png"));

المان نمایش سلسله‌مراتب پیچیده درختی (مشابه درخت پروژه گودو) که برای پیاده‌سازی پورتال‌ها، گزینه‌های مجهز به زیرمجموعه و منوهای حرفه‌ای بکار می‌رود.

C#:
TreeItem root = CreateItem(); root.SetText(0, "شاخه اصلی");

نوار ابزار بومی بالای کادر برای ویندوزها و سیستم‌عامل‌ها که به ازای هر زیرمنوی مجهز به PopupMenu یک گزینه بازشو در نوار منوی بومی یا کلاینت ایجاد می‌کند.

C#:
PreferGlobalMenu = true;

دکمه‌ای مجهز به منوی آبشاری متصل که با کلیک روی آن بلافاصله یک شیء PopupMenu با گزینه‌های دلخواه رندر می‌شود.

C#:
GetPopup().AddItem("ذخیره بازی");

منوی مدال شناور دارای لیست ورودی‌های فشرده و بهینه‌سازی شده برای پیاده‌سازی راست‌کلیک‌ها و میانبرهای دسترسی سریع منوی کاربری.

C#:
PopupCenteredClamped();
